INSERT INTO `filter` (`id`, `name`, `opis`, `slug`) VALUES
(4, 'Dosatron', 'Дозаторы-медикаторы Dosatron — это высокоточное оборудование для автоматического дозирования жидкостей в системах водоснабжения. Продукция бренда Dosatron широко применяется в сельском хозяйстве, животноводстве, птицеводстве и промышленности.  В нашем ассортименте представлены популярные модели, такие как дозатрон d25re2, дозатрон d25re5 для задач средней производительности, а также профессиональные решения, включая дозатрон d3re10 vvf.  Актуальная цена медикатора дозатрон  зависит от модели и характеристик, уточняйте на сайте.   Выбирая дозатор dosatron, вы получаете надежное решение для эффективного и стабильного дозирования жидкостей.', 'dosatron'),
(5, 'MASTER PRO', 'Медикаторы MASTER PRO — это уникальный дозирующий насос, предназначенный для точного дозирования различных ветпрепаратов и жидких кормовых добавок. Дозирующие насосы бренда MASTER PRO широко применяются в сельском хозяйстве, животноводстве и птицеводстве, где требуется стабильная подача удобрений, медикаментов или других жидкостей.  Инжекторы медикатора MASTER PRO легко адаптируются, просты в использовании и экономически эффективны, что немаловажно для эффективного и долгосрочного планирования.  Базовый ремонтный комплект прилагается к каждому медикатору MASTER PRO. Простая замена уплотнительных колец.', 'master-pro'),
(6, 'MixRite', 'Дозаторы-медикаторы MixRite — это профессиональное оборудование для точного дозирования жидких добавок и ветпрепаратов в системах водоснабжения. Бренд MixRite зарекомендовал себя как надежный производитель решений для сельского хозяйства, животноводства, тепличных комплексов и промышленности, где требуется стабильная и точная подача растворов.  В нашем каталоге представлены популярные дозаторы MixRite, включая модели MixRite 2.5, Tefen MixRite 2.5, а также более производительные решения, такие как Tefen MixRite 10 и современный дозатор MixRite G3.   Если вы планируете купить медикатор для эффективного внесения удобрений, витаминов или ветеринарных препаратов, дозаторы MixRite станут оптимальным выбором.   Выбирая дозаторы-медикаторы MixRite, вы получаете проверенное решение для автоматизации процессов дозирования и повышения эффективности вашего бизнеса.', 'mixrite'),
(7, 'Узел водоподготовки', 'Узел водоподготовки и дозирования медикаментов – это комплексное решение для обеспечения качественного водоснабжения и точного дозирования лекарственных препаратов в системах поения. Этот узел идеально подходит для использования на фермах, животноводческих комплексах и птицефабриках, обеспечивая надежную и эффективную работу.  Узел водоподготовки обеспечивает фильтрацию, контроль и учет питьевой воды, потребляемой птицей, а также ввод в ее состав растворимых препаратов для выпаивания птицы.', 'uzel-vodopodgotovki'),
(8, 'MixTron', 'Дозаторы-медикаторы MixTron — это современное решение для точного и надежного дозирования жидких добавок в системах водоснабжения. Продукция бренда MixTron широко применяется в сельском хозяйстве, животноводстве, тепличных хозяйствах и промышленности, где требуется стабильная подача удобрений, медикаментов или других жидкостей.  В нашем ассортименте представлены оригинальные дозаторы MixTron, включая популярную модель Mixtron MX 300, которая отличается высокой производительностью, простотой настройки и долговечностью. Все дозаторы-медикаторы работают без электричества, используя давление воды, что делает их экономичным и удобным решением для различных задач.  Если вы планируете купить медикатор для профессионального или бытового использования, оборудование MixTron станет оптимальным выбором благодаря точности дозирования и надежной конструкции. Также в наличии всегда есть запасные части к дозаторам MixTron, что позволяет продлить срок службы оборудования и минимизировать простои.  Дозаторы MixTron — это эффективный дозирующий насос, который обеспечивает стабильное смешивание и подачу растворов в нужной пропорции. Выбирая продукцию MixTron, вы получаете качество, проверенное временем, и высокую эффективность в работе.', 'mixtron'),
(9, 'Save Water', 'Дозаторы-медикаторы SaveWater — это надежное оборудование для точного дозирования жидкостей в системах водоснабжения. Они широко используются в сельском хозяйстве, животноводстве, птицеводстве и тепличных комплексах, где важно обеспечить равномерную подачу удобрений, витаминов и лекарственных растворов.  Дозаторы-медикаторы SaveWater работают по принципу гидропривода и не требуют подключения к электросети, что делает их удобными и экономичными в эксплуатации. Такой дозирующий насос обеспечивает стабильную пропорцию смешивания независимо от давления воды, гарантируя высокую точность и эффективность работы.  Выбирая SaveWater, вы получаете качественные дозаторы-медикаторы, которые помогают оптимизировать процессы дозирования и повысить эффективность вашего хозяйства или производства.', 'save-water');
