INSERT INTO `medicator` (`id`, `name`, `d_dosing`, `performance`, `pressure`, `temperature`, `connections`, `m_seal`, `m_case`, `dop`, `passport`, `user_pass`, `opis`, `filtr`, `slug`) VALUES
(1, 'Dosatron DIA4AL VF', '0.2 — 2 % [1:500 — 1:50]', '10 л/ч — 2.5 м³/ч', '0.3 — 6 бар', '5 — 40 °C', 'G¾\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Полиацеталь', '-', '697cbccb49dc2_Manual_Notice_DIAAL_EN-1.pdf', NULL, 'DIA4AL (серия Animal Health Line) – это новейшая разработка компании Dosatron и новое слово в неэлектрическом пропорциональном дозировании. Уникальный мембранный двигатель позволяет решить ряд принципиальных проблем дозирования препаратов в птицеводстве и свиноводсте. Дозаторон может работать при чрезвычайно малом расходе воды, что делает его незаменимым для поения молодняка. Низкое рабочее давление позволяет использовать его даже в системе с водонапорным баком на высоте всего 1.5 метра. А конструкция двигателя с минимальным количеством деталей подверженных трению, делает возможным применение дозатрона DIA4AL даже если поступающая вода имеет высокое содержание минеральных примесей.', 'DIA', 'dosatron-dia4al-vf'),
(2, 'Dosatron D07RE125AF', '0.15 — 1.25 % [1:666 — 1:80]', '5 л/ч — 0.7 м³/ч', '0.3 — 6 бар', '5 — 40 °C', 'G¾\" наружная', 'AFLAS – уплотнения, устойчивые к щелочам, для дозирования жидкостей со значением pH более 8', 'Полиацеталь', 'Встроенный by-pass', '697cbd54a3290_Eclate-D07RE125-u.pdf', NULL, 'Серия D07 Compact – это самые малогабаритные неэлектрические пропорциональные дозаторы. Их используют в тех случаях, когда не требуется высокая производительность и сильно ограничено пространство для установки. Часто находят свое применение в составе более сложных агрегатов.', 'D07', 'dosatron-d07re125af'),
(3, 'Dosatron D07RE5AF', '0.8 — 5.5 % [1:128 — 1:28]', '5 л/ч — 0.7 м³/ч', '0.3 — 6 бар', '5 — 40 °C', 'G¾\" наружная', 'AFLAS – уплотнения, устойчивые к щелочам, для дозирования жидкостей со значением pH более 8', 'Полиацеталь', 'Встроенный by-pass', '697cbd905ab83_Eclate-D07RE5-u.pdf', NULL, 'Серия D07 Compact – это самые малогабаритные неэлектрические пропорциональные дозаторы. Их используют в тех случаях, когда не требуется высокая производительность и сильно ограничено пространство для установки. Часто находят свое применение в составе более сложных агрегатов.', 'D07', 'dosatron-d07re5af'),
(4, 'D25AL2 NVF', '0.2 — 2 % [1:500 — 1:50]', '10 л/ч — 2.5 м³/ч', '0.3 — 6 бар', '5 — 40°C', 'G¾\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Специальный полипропилен', 'NSF cертификация для контакта с пищевыми продуктами', '697cbe3d42d71_Rangesheet_FichesGamme_D25_EN-1.pdf', NULL, 'Инновационный дозатор D25AL2N (серия Animal Health Line), также известный как D25+Care, с производительностью от 10 до 2500 л/ч обладает большей химической стойкостью и расширенным диапазоном дозирования по сравнению с классической моделью D25RE2.', 'D25', 'd25al2-nvf'),
(5, 'D25AL5 NVF', '1 — 5 % [1:100 — 1:20]', '10 л/ч — 2.5 м³/ч', '0.3 — 6 бар', '5 — 40°C', 'G¾\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Специальный полипропилен', 'NSF cертификация для контакта с пищивыми продуктами', '697cbeb85e873_Rangesheet_FichesGamme_D25_EN-1.pdf', NULL, 'Инновационный дозатор D25AL5N (серия Animal Health Line), также известный как D25+Care, с производительностью от 10 до 2500 л/ч обладает большей химической стойкостью и расширенным диапазоном дозирования по сравнению с классической моделью D25RE5.', 'D25', 'd25al5-nvf'),
(8, 'D25RE09 AO', '0.1 — 0.9 % [1:1000 — 1:112]', '10 л/ч — 2.5 м³/ч', '0.3 — 6 бар', '5 — 40 °C', 'G¾\" наружная', 'Специальные химически стойкие уплотнения для дозирования концентрированных органических кислот', 'Поливинилиденфторид (ПВДФ/PVDF)', 'AO - корпус и уплотнения с высокой химической стойкостью для дозирования концентрированных органических кислот', '697cbef80b15b_Rangesheet_FichesGamme_D25_EN-1.pdf', NULL, 'AO - это особая модификация дозирующих насосов серии D25, предназначенная для дозирования концентрированных органических кислот. Для того, чтобы выдержать подобное агрессивное воздействие, дозатрон снабжен корпусом из ПВДФ, который обладает гораздо большей хим- и износостойкостью, чем традиционный для серии D25 полиацеталь. Кроме того используется специальный набор уплотнений.', 'D25', 'd25re09-ao'),
(9, 'Дозатрон D25RE2 AO', '0.2 — 2 % [1:500 — 1:50]', '10 л/ч — 2.5 м³/ч', '0.3 — 6 бар', '5 — 40 °C', 'G¾\" наружная', 'Специальные химически стойкие уплотнения для дозирования концентрированных органических кислот', 'Поливинилиденфторид', 'AO - корпус и уплотнения с высокой химической стойкостью для дозирования концентрированных органических кислот', '696e49bf94d95_D25RE2.pdf', NULL, 'AO - это особая модификация дозирующих насосов серии D25, предназначенная для дозирования концентрированных органических кислот. Для того, чтобы выдержать подобное агрессивное воздействие, дозатрон снабжен корпусом из ПВДФ, который обладает гораздо большей хим- и износостойкостью, чем традиционный для серии D25 полиацеталь.', 'D25', 'd25re2-ao'),
(10, 'Дозатрон D25RE1500 VF', '0.07 — 0.2 % [1:1500 — 1:500]', '10 л/ч — 2.5 м³/ч', '0.3 — 6 бар', '5 — 40 °C', 'G¾\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Полиацеталь', '-', '696e4bcd46d15_D25RE1500.pdf', NULL, 'D25RE1500 имеет наименьшую дозировку среди дозатронов серии D25. Используется в тех случаях когда в воду необходимо добавить очень незначительную долю реагента. Приготовление подобных растворов другими методами связано с большими трудностями.', 'D25', 'd25re1500-vf'),
(11, 'Дозатрон D25RE1500 AF', '0.07 — 0.2 % [1:1500 — 1:500]', '10 л/ч — 2.5 м³/ч', '0.3 — 6 бар', '5 — 40 °C', 'G¾\" наружная', 'AFLAS – уплотнения, устойчивые к щелочам, для дозирования жидкостей со значением pH более 8', 'Полиацеталь', '-', '696e4bbfb327d_D25RE1500.pdf', NULL, 'D25RE1500 имеет наименьшую дозировку среди дозатронов серии D25. Используется в тех случаях когда в воду необходимо добавить очень незначительную долю реагента. Приготовление подобных растворов другими методами связано с большими трудностями.', 'D25', 'd25re1500-af'),
(12, 'Дозатрон D25RE2 VF', '0.2 — 2 % [1:500 — 1:50]', '10 л/ч — 2.5 м³/ч', '0.3 — 6 бар', '5 — 40 °C', 'G¾\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Полиацеталь', '-', '696e4c2d96034_D25RE2.pdf', NULL, 'Модель D25RE2 VF – это наиболее востребованная в модель в птицеводстве. Применяется для дозирования противоинфекционных и противопаразитных средств, вакцин, пищевых добавок, пробиотиков, неконцентрированных кислот и др.. Именно поэтому вместо дозатор часто употребляется термин медикатор. Тонкий всасывающий шланг не подходит для дозирования вязких жидкостей.', 'D25', 'd25re2-vf'),
(13, 'Дозатрон D25RE2 AF', '0.2 — 2 % [1:500 — 1:50]', '10 л/ч — 2.5 м³/ч', '0.3 — 6 бар', '5 — 40 °C', 'G¾\" наружная', 'AFLAS – уплотнения, устойчивые к щелочам, для дозирования жидкостей со значением pH более 8', 'Полиацеталь', '-', '696e4c9e0da49_D25RE2.pdf', NULL, 'Модель D25RE2 AF предназначена для дозирования жидкостей обладающих щелочными свойствами. Стоит обратить внимание, что тонкий, 6-миллиметровый всасывающий шланг ограничивает применение данной модели для дозирования вязких жидкостей.', 'D25', 'd25re2-af'),
(14, 'Дозатрон D25RE5 VF', '1 — 5 % [1:100 — 1:20]', '10 л/ч — 2.5 м³/ч', '0.3 — 6 бар', '5 — 40°C', 'G¾\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Полиацеталь', '-', '696e4d2f2bfad_D25RE5.pdf', NULL, 'Модель D25RE5 VF имеет наибольшее распространение в свиноводстве, но также набирает популярность и в птицеводстве. Применяется для дозирования противоинфекционных и противопаразитных средств, вакцин, пищевых добавок, пробиотиков, неконцентрированных кислот и др.. Именно поэтому вместо дозатор часто употребляется термин медикатор. Широкий диапазон дозирования позволяет использовать менее концентрированные маточные растворы, что в свою очередь улучшает растворимость препаратов.', 'D25', 'd25re5-vf'),
(15, 'Дозатрон D25RE10 VF', '3 — 10 % [1:33 — 1:10]', '10 л/ч — 2 м³/ч', '0.3 — 4 бар', '5 — 40°C', 'G¾\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Полиацеталь', '-', '696e4e7d1ffd7_D25RE5.pdf', NULL, 'D25RE10 VF предназначена для дозирования неконцентрированных кислот, противоинфекционных и противопаразитных средств, вакцин, пищевых добавок, пробиотиков и др.. Именно поэтому вместо дозатор часто употребляется термин медикатор. К преимуществам модели можно отнести диапазон дозирования от 3 до 10%, что является максимумом для серии D25. Но ради увеличения верхней границы диапазона пришлось пожертвовать производительностью (до 2 м³/ч) и максимальным рабочим давлением (до 4 бар).', 'D25', 'd25re10-vf'),
(16, 'Дозатрон D25RE10 AF', '3 — 10 % [1:33 — 1:10]', '10 л/ч — 2 м³/ч', '0.3 — 4 бар', '5 — 40°C', 'G¾\" наружная', 'AFLAS – уплотнения, устойчивые к щелочам, для дозирования жидкостей со значением pH более 8', 'Полиацеталь', '-', '696e4ecd2bc61_D25RE5.pdf', NULL, 'D25RE10 AF предназначена для дозирования щелочных моющих средств. К преимуществам модели можно отнести диапазон дозирования от 3 до 10%, что является максимумом для серии D25. Но ради увеличения верхней границы диапазона пришлось пожертвовать производительностью (до 2 м³/ч) и максимальным рабочим давлением (до 4 бар).', 'D25', 'd25re10-af'),
(17, 'Дозатрон D25RE10IE AF', '3 — 10 % [1:33 — 1:10]', '10 л/ч — 2 м³/ч', '0.3 — 4 бар', '5 — 40°C', 'G¾\" наружная', 'AFLAS – уплотнения, устойчивые к щелочам, для дозирования жидкостей со значением pH более 8', 'Полиацеталь', '-', '696e4f9702935_D25RE5.pdf', NULL, 'Модель D25RE10IE AF оснащена комплектом для внешней инжекции. Это означает, что концентрат добавляется в воду непосредственно на выходе, т.е. минуя двигатель. Таким образом исключается воздействие концентрата на детали двигателя, что позволяет дозировать более агрессивные жидкости. Диапазон дозирования от 3 до 10%, что является максимумом для серии D25, но ради увеличения верхней границы диапазона пришлось пожертвовать производительностью (до 2 м³/ч) и максимальным рабочим давлением (до 4 бар).', 'D25', 'd25re10ie-af'),
(18, 'Дозатрон D25WL2IE VVFPO', '0.2 — 2 % [1:500 — 1:50]', '10 л/ч — 2,5 м³/ч', '0.3 — 6 бар', '5 — 40°C', 'G¾\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Полиацеталь', '-', '696e502bc791f_D25RE5.pdf', NULL, 'Модель D25WL2IE VVFPO специально разработана для дозирования полимеров, применяемых при очистке воды. Высокая вязкость полимеров не позволяет использовать для этой цели стандартный модели, поскольку концентрат остается в двигателе дозатора и быстро выводит его из строя. Для того, чтобы избежать этого, дозатор оснащен системой внешней инжекцией специальной конструкции. Кроме того, модель снабжена всасывающей трубкой увеличенного диаметра, что также является необходимым требованием при работе с концентратами высокой вязкости.', 'D25', 'd25wl2ie-vvfpo'),
(19, 'Дозатрон D3GL3000 VF', '0.03 — 0.3 % [1:3000 — 1:333]', '10 л/ч — 3 м³/ч', '0.3 — 6 бар', '5 — 40 °C', 'G¾\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Специальный полипропилен', '-', '69775f9ba4440_Manual_D3GL.pdf', NULL, 'Серия Green Line специально разработана для применения в области растениеводства. Корпус зеленого цвета меньше подвержен воздействию интенсивного освещения и длительное время сохраняет эстетичный внешний вид. Резиновые уплотнения из VITON', 'D3', 'd3gl3000-vf'),
(24, 'Дозатрон D3GL2 VF', '0.2 — 2 % [1:500 — 1:50]', '10 л/ч — 3 м³/ч', '0.3 — 6 бар', '5 — 40°C', 'G¾\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Специальный полипропилен', '-', '6979c4878d908_1769587847_Manual_D3GL.pdf', NULL, 'Серия Green Line специально разработана для применения в области растениеводства. Корпус зеленого цвета меньше подвержен воздействию интенсивного освещения и длительное время сохраняет эстетичный внешний вид. Резиновые уплотнения из VITON\'a идеально подходят для жидких удобрений и минеральных добавок.', 'D3', 'd3gl2-vf'),
(26, 'Дозатрон D3GL5 VF', '0.5 — 5 % [1:200 — 1:20]', '10 л/ч — 3 м³/ч', '0.3 — 6 бар', '5 — 40°C', 'G¾\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Специальный полипропилен', '-', '6979ca1862496_1769589272_Manual_D3GL.pdf', NULL, 'Серия Green Line специально разработана для применения в области растениеводства. Корпус зеленого цвета меньше подвержен воздействию интенсивного освещения и длительное время сохраняет эстетичный внешний вид. Резиновые уплотнения из VITON\'a идеально подходят для жидких удобрений и минеральных добавок.', 'D3', 'd3gl5-vf'),
(27, 'Дозатрон D3GL2 BPVF', '0.2 — 2 % [1:500 — 1:50]', '10 л/ч — 3 м³/ч', '0.3 — 6 бар', '5 — 40°C', 'G¾\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Специальный полипропилен', 'Переключатель by-pass', '6979cac475b55_1769589444_Manual_D3GL.pdf', NULL, 'Серия Green Line специально разработана для применения в области растениеводства. Корпус зеленого цвета меньше подвержен воздействию интенсивного освещения и длительное время сохраняет эстетичный внешний вид. Резиновые уплотнения из VITON\'a идеально подходят для жидких удобрений и минеральных добавок. Встроенный переключатель by-pass позволяет без установки дополнительных кранов и трубопроводной арматуры производить запуск и остановку двигателя дозатора. Данная опция особенно удобна при использовании дозаторов в фертигационных узлах с возможностью одновременного введения нескольких добавок.', 'D3', 'd3gl2-bpvf'),
(28, 'D3GL10 VF', '1 — 10 % [1:100 — 1:10]', '10 л/ч — 3 м³/ч', '0.5 — 6 бар', '5 — 40°C', 'G¾\" наружная', 'VITON – для кислот, масел, ароматических веществ и пестицидов', 'Специальный полипропилен', '-', '6979cb44b90ae_1769589572_Manual_D3GL.pdf', NULL, 'Серия Green Line специально разработана для применения в области растениеводства. Корпус зеленого цвета меньше подвержен воздействию интенсивного освещения и длительное время сохраняет эстетичный внешний вид. Резиновые уплотнения из VITON\'a идеально подходят для жидких удобрений и минеральных добавок.', 'D3', 'd3gl10vf'),
(29, 'Дозатрон D3RE2 VFKP', '0.2 — 2 % [1:500 — 1:50]', '10 л/ч — 3 м³/ч', '0.3 — 6 бар', '5 — 40 °C', 'G¾\" наружная', 'FFKM - cпециальные химически стойкие уплотнения для дозирования концентрированных кислот', 'Поливинилиденфторид (ПВДФ/PVDF)', 'KP - корпус и уплотнения с высокой химической стойкостью для дозирования концентрированных кислот', NULL, NULL, 'KP - это особая модификация дозирующих насосов серии D3, предназначенная для дозирования концентрированных кислот. Для того, чтобы выдержать подобное агрессивное воздействие, дозатрон снабжен корпусом из ПВДФ, который обладает большей хим- и износостойкостью, чем специальный полипропилен стандартной комплектации серии D3. Также используется специальный набор уплотнений из высококачественного перфторэластомера FFKM.', 'D3', 'd3re2-vfkp'),
(30, 'Дозатрон D3RE2 BPVFKP', '0.2 — 2 % [1:500 — 1:50]', '10 л/ч — 3 м³/ч', '0.3 — 6 бар', '5 — 40 °C', 'G¾\" наружная', 'FFKM - cпециальные химически стойкие уплотнения для дозирования концентрированных кислот', 'Поливинилиденфторид (ПВДФ/PVDF)', 'BP - переключатель by-pass KP - корпус и уплотнения с высокой химической стойкостью для дозирования концентрированных кислот', NULL, NULL, 'KP - это особая модификация дозирующих насосов серии D3, предназначенная для дозирования концентрированных кислот. Для того, чтобы выдержать подобное агрессивное воздействие, дозатрон снабжен корпусом из ПВДФ, который обладает большей хим- и износостойкостью, чем специальный полипропилен стандартной комплектации серии D3. Также используется специальный набор уплотнений из высококачественного перфторэластомера FFKM. Встроенный переключатель by-pass позволяет без установки дополнительных кранов и трубопроводной арматуры производить запуск и остановку двигателя дозатора.', 'D3', 'd3re2-bpvfkp'),
(31, 'Дозатрон D3RE3000 VFKP', '0.03 — 0.3 % [1:3000 — 1:333]', '10 л/ч — 3 м³/ч', '0.3 — 6 бар', '5 — 40 °C', 'G¾\" наружная', 'FFKM - cпециальные химически стойкие уплотнения для дозирования концентрированных кислот', 'Поливинилиденфторид (ПВДФ/PVDF)', 'KP - корпус и уплотнения с высокой химической стойкостью для дозирования концентрированных кислот', NULL, NULL, 'KP - это особая модификация дозирующих насосов серии D3, предназначенная для дозирования концентрированных кислот. Для того, чтобы выдержать подобное агрессивное воздействие, дозатрон снабжен корпусом из ПВДФ, который обладает большей хим- и износостойкостью, чем специальный полипропилен стандартной комплектации серии D3. Также используется специальный набор уплотнений из высококачественного перфторэластомера FFKM.', 'D3', 'd3re3000-vfkp'),
(33, 'Дозатрон D3WL3000IE', '0.03 — 0.3 % [1:3000 — 1:333]', '10 л/ч — 3 м³/ч', '0.3 — 6 бар', '5 — 40 °C', 'G¾\" наружная', 'AFLAS – уплотнения, устойчивые к щелочам, для дозирования жидкостей со значением pH более 8', 'Специальный полипропилен', 'Мембранная система внешней инжекции', '697a048da5152_1769604237_Manual_D3WL.pdf', NULL, 'Серия дозаторов Water Line специально разработана компанией Dosatron для решения определенных задач водоподготовки. Модель D3WL3000IE предназначена в первую очередь для хлорирования воды. Неэлектрический двигатель, простая и надежная конструкция позволяют легко решить задачу обеззараживания воды с минимумом усилий и в кратчайшие сроки. Уникальная мембранная система внешней инжекции исключает попадание хлора внутрь двигателя дозатора, значительно увеличивает срок службы насоса и упрощает его обслуживание. Широкие диапазоны производительности и рабочего давления позволяют применять данный насос даже в условиях подачи воды самотеком. Дозатор одновременно является счетчиком воды и выставленная на ручном регуляторе пропорция дозирования будет сохраняться вне зависимости от колебаний потока и давления воды.', 'D3', 'd3wl3000ie'),
(34, 'Дозатрон D3RE3000 AF', '0.03 — 0.3 % [1:3000 — 1:333]', '10 л/ч — 3 м³/ч', '0.3 — 6 бар', '5 — 40 °C', 'G¾\" наружная', 'AFLAS – уплотнения, устойчивые к щелочам, для дозирования жидкостей со значением pH более 8', 'Специальный полипропилен', '-', '697a0506e10ee_1769604358_Manual_D3WL.pdf', NULL, 'Серия D3 - это современные дозатроны для промышленного применения. Надежный двигатель в сочетании с корпусом повышенной химической стойкости существенно увеличивает срок службы. Дозатрон содержит меньше деталей, и его обслуживание стало значительно проще. Новая эргономичная дозирующая система упрощает регулирование дозировки. Модель D3RE3000 AF обладает минимальным пределом дозирования среди всех дозатронов и способна добавить в воду всего 3 сотых процента концентрата. Уплотнения из уникального фторэластомера AFLAS идеально подходят для дозирования щелочей и спиртов.', 'D3', 'd3re3000-af'),
(35, 'Dosatron D3RE2 AF', '0.2 — 2 % [1:500 — 1:50]', '10 л/ч — 3 м³/ч', '0.3 — 6 бар', '5 — 40°C', 'G¾\" наружная', 'AFLAS – уплотнения, устойчивые к щелочам, для дозирования жидкостей со значением pH более 8', 'Специальный полипропилен', '-', '697a099f6f578_1769605535_Manual_D3.pdf', NULL, 'D3RE2 AF - это современная замена модели D25RE2 AF. Надежный двигатель в сочетании с корпусом повышенной химической стойкости существенно увеличивает срок службы. Дозатрон содержит меньше деталей, и его обслуживание стало значительно проще. Новая эргономичная дозирующая система упрощает регулирование дозировки. В отличие от D25RE2, диаметр всасывающего шланга у модели D3RE2 составляет 8-миллиметров, что позволяет работать с более вязкими концентратами.', 'D3', 'dosatron-d3re2-af'),
(36, 'Dosatron D3RE2 VF', '0.2 — 2 % [1:500 — 1:50]', '10 л/ч — 3 м³/ч', '0.3 — 6 бар', '5 — 40°C', 'G¾\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Специальный полипропилен', '-', '697a0a44c7135_1769605700_Manual_D3.pdf', NULL, 'Серия D3 - это современные дозатроны для промышленного применения. Надежный двигатель в сочетании с корпусом повышенной химической стойкости существенно увеличивает срок службы. Дозатрон содержит меньше деталей, и его обслуживание стало значительно проще. Новая эргономичная дозирующая система упрощает регулирование дозировки.', 'D3', 'dosatron-d3re2-vf'),
(38, 'Dosatron D3RE5 AF', '0.5 — 5 % [1:200 — 1:20]', '10 л/ч — 3 м³/ч', '0.3 — 6 бар', '5 — 40°C', 'G¾\" наружная', 'AFLAS – уплотнения, устойчивые к щелочам, для дозирования жидкостей со значением pH более 8', 'Специальный полипропилен', '-', '697a0bf444e7d_1769606132_Manual_D3.pdf', NULL, 'D3RE5 AF - это современная замена модели D25RE5 AF. Надежный двигатель в сочетании с корпусом повышенной химической стойкости существенно увеличивает срок службы. Дозатрон содержит меньше деталей, и его обслуживание стало значительно проще. Новая эргономичная дозирующая система упрощает регулирование дозировки. Диапазон дозирования увеличен, а 12-миллиметровый всасывающий шланг позволяет работать с практически любой автохимией.', 'D3', 'dosatron-d3re5-af'),
(40, 'Dosatron D3RE5 VF', '0.5 — 5 % [1:200 — 1:20]', '10 л/ч — 3 м³/ч', '0.3 — 6 бар', '5 — 40°C', 'G¾\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Специальный полипропилен', '-', '697b3b3d06977_1769683773_Manual_D3.pdf', NULL, 'Серия D3 - это современные дозатроны для промышленного применения. Надежный двигатель в сочетании с корпусом повышенной химической стойкости существенно увеличивает срок службы. Дозатрон содержит меньше деталей, и его обслуживание стало значительно проще. Новая эргономичная дозирующая система упрощает регулирование дозировки.', 'D3', 'dosatron-d3re5-vf'),
(41, 'Dosatron D3RE10 AF', '0.5 — 5 % [1:200 — 1:20]', '10 л/ч — 3 м³/ч', '0.3 — 6 бар', '5 — 40°C', 'G¾\" наружная', 'AFLAS – уплотнения, устойчивые к щелочам, для дозирования жидкостей со значением pH более 8', 'Специальный полипропилен', '-', '697b3c09ba7d8_1769683977_Manual_D3.pdf', NULL, 'D3RE10 AF предназначена для дозирования щелочных моющих средств. Преимуществом модели является широкий от 1 до 10% диапазон дозирования. При этом в отличии от D25RE10 AF, здесь высокая граница диапазона не сказывается на рабочем давлении и производительности.', 'D3', 'dosatron-d3re10-af'),
(42, 'Dosatron D3RE10 VF', '1 — 10 % [1:100 — 1:10]', '10 л/ч — 3 м³/ч', '0.5 — 6 бар', '5 — 40°C', 'G¾\" наружная', 'VITON – для кислот, масел, ароматических веществ и пестицидов', 'Специальный полипропилен', '-', '697b3c9868d1d_1769684120_Manual_D3.pdf', NULL, 'Серия D3 - это современные дозатроны для промышленного применения. Надежный двигатель в сочетании с корпусом повышенной химической стойкости существенно увеличивает срок службы. Дозатрон содержит меньше деталей, и его обслуживание стало значительно проще. Новая эргономичная дозирующая система упрощает регулирование дозировки.', 'D3', 'dosatron-d3re10-vf'),
(43, 'Dosatron D3RE10 VVF', '1 — 10 % [1:100 — 1:10]', '10 л/ч — 3 м³/ч', '0.5 — 6 бар', '5 — 40°C', 'G¾\" наружная', 'VITON – для кислот, масел, ароматических веществ и пестицидов', 'Специальный полипропилен', 'Комплект для вязких концентратов', '697b3cf743918_1769684215_Manual_D3.pdf', NULL, 'Модель D3RE10VVF специально адаптирована для приготовления СОЖ (смазочно-охлаждающая жидкость) для металлообрабатывающей промышленности. Широкий диапазон дозирования, усиленный всасывающий шланг и всасывающий клапан большого диаметра позволяют работать с практически любой современной СОЖ, представленной на рынке. Высокий ресурс серии D3 позволит приготовить до 4.5 млн. литров без обслуживания двигателя дозатора.', 'D3', 'dosatron-d3re10-vvf'),
(44, 'Dosatron D3RE25IE VF', '5 — 25 % [1:20 — 1:4]', '10 л/ч — 2 м³/ч', '0.5 — 4 бар', '5 — 40°C', 'G¾\" наружная', 'VITON – для кислот, масел, ароматических веществ и пестицидов', 'Специальный полипропилен', 'Внешняя инжекция', '697b3d843c118_1769684356_Manual_D3.pdf', NULL, 'D3RE25IE - это уникальная во всех отношениях модель имеет максимальную границу диапазона дозирования 25%, что является абсолютным рекордом среди неэлектрических дозирующих насосов. Обеспечение такой высокой дозировки потребовало установки системы внешней инжекции, т.е. концентрат не попадает внутрь двигителя дозатора, а впрыскивается в воду уже на выходе из дозатрона. По сравнению с другими моделями серии у D3RE25IE меньше производительность (до 2 м³/ч) и максимальное рабочее давление (до 4 бар). D3RE25IE является современной заменой также уникальному в свое время дозатрону DI520. Стоит отметить, что дозирующие насосы Dosatron являются пропорционально волюметрическими, и при дозировке 25% к 100% воды будет добавленно 25% концентрата, таким образом, во всем объеме раствора будет 25/(100+25) долей концентрата, т.е. 20%. Это справедливо для любого дозатрона, но чем больше диапазон дозирования, тем больше заметна эта разница.', 'D3', 'dosatron-d3re25ie-vf'),
(45, 'Dosatron D6AL2 VF', '0.2 — 2 % [1:500 — 1:50]', '100 л/ч — 6 м3/ч', '0.3 — 8 бар', '5 — 40°C', 'G¾\" наружная', 'VITON – для кислот, масел, ароматических веществ и пестицидов', 'Специальный полипропилен', '-', NULL, NULL, 'Серия D6 - это новейшая разработка, призванная заменить собой серию D45. Модель D6AL2 (серия Animal Health Line) воплощает в себе все последние наработки, а также содержит новый уникальный элемент - сменный вкладыш корпуса. Благодаря этому нововведению, последствия механического износа теперь могут быть устранены без замены всего корпуса дозатора, что в свою очередь не только снижает стоимость, но и увеличивает скорость ремонта. Также стоит отметить широкий диапазон производительности, который позволяет работать как и при достаточно низком потреблении от 100 л/ч, так и выдерживать высокие нагрузки до 6 м3/ч.', 'D6', 'dosatron-d6al2-vf'),
(46, 'Dosatron D6GL2 BPVF', '0.2 — 2 % [1:500 — 1:50]', '100 л/ч — 6 м3/ч', '0.3 — 8 бар', '5 — 40°C', 'G1¼\" наружная', 'VITON – для кислот, масел, ароматических веществ и пестицидов', 'Специальный полипропилен', 'Переключатель by-pass', NULL, NULL, 'Серия Green Line специально разработана для применения в области растениеводства. Корпус зеленого цвета меньше подвержен воздействию интенсивного освещения и длительное время сохраняет эстетичный внешний вид. Резиновые уплотнения из VITON\'a идеально подходят для жидких удобрений и минеральных добавок. Серия D6 - это новейшая разработка, призванная заменить собой серию D45. Модель воплощает в себе все последние наработки, а также содержит новый уникальный элемент - сменный вкладыш корпуса. Благодаря этому нововведению, последствия механического износа теперь могут быть устранены без замены всего корпуса дозатора, что в свою очередь не только снижает стоимость, но и увеличивает скорость ремонта. Также стоит отметить широкий диапазон производительности, который позволяет работать как и при достаточно низком потреблении от 100 л/ч, так и выдерживать высокие нагрузки до 6 м3/ч.', 'D6', 'dosatron-d6gl2-bpvf'),
(47, 'Dosatron D45RE3000 VF', '0.03 — 0.1 % [1:3000 — 1:1000]', '100 л/ч — 4.5 м3/ч', '0.5 — 5 бар', '5 — 40 °C', 'G1¼\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Полиацеталь', 'Встроенный by-pass', '697b3f9291e05_1769684882_Manual_D45.pdf', NULL, 'Дозаторы серии D45 находят применение в животноводческих хозяйствах с большим поголовьем. Подходят для ситуаций когда производительности популярной серии D25 оказывается недостаточно. Модель D45RE3000 VF обладает минимальным пределом дозирования среди всех дозатронов и способна добавить в воду всего 3 сотых процента концентрата.', 'D45', 'dosatron-d45re3000-vf'),
(48, 'Dosatron D45RE15 VF', '0.2 — 1.5 % [1:500 — 1:66]', '100 л/ч — 4.5 м3/ч', '0.5 — 5 бар', '5 — 40 °C', 'G1¼\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Полиацеталь', 'Встроенный by-pass', '697b410b2a9c2_1769685259_Manual_D45.pdf', NULL, 'Дозаторы серии D45 находят применение в животноводческих хозяйствах с большим поголовьем. Подходят для ситуаций когда производительности популярной серии D25 оказывается недостаточно.', 'D45', 'dosatron-d45re15-vf'),
(49, 'Dosatron D45RE3 VF', '0.5 — 3 % [1:200 — 1:33]', '100 л/ч — 4.5 м3/ч', '0.5 — 5 бар', '5 — 40 °C', 'G1¼\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Полиацеталь', 'Встроенный by-pass', '697b50a1c331b_1769689249_Manual_D45.pdf', NULL, 'Дозаторы серии D45 находят применение в животноводческих хозяйствах с большим поголовьем. Подходят для ситуаций когда производительности популярной серии D25 оказывается недостаточно.', 'D45', 'dosatron-d45re3-vf'),
(50, 'Dosatron D45RE3 AF', '0.5 — 3 % [1:200 — 1:33]', '100 л/ч — 4.5 м3/ч', '0.5 — 5 бар', '5 — 40 °C', 'G1¼\" наружная', 'AFLAS – уплотнения, устойчивые к щелочам, для дозирования жидкостей со значением pH более 8', 'Полиацеталь', 'Встроенный by-pass', '697b5140a5d53_1769689408_Manual_D45.pdf', NULL, 'Дозаторы D45 находят применение там, где производительности популярной серии D25 оказывается недостаточно. Данная модель преимущественно используется на крупных автомоечных комплексах.', 'D45', 'dosatron-d45re3-af'),
(51, 'Dosatron D45RE8 VF', '3 — 8 % [1:33 — 1:12]', '100 л/ч — 4.5 м3/ч', '0.5 — 5 бар', '5 — 40 °C', 'G1¼\" наружная', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Полиацеталь', 'Встроенный by-pass', '697b52261070a_1769689638_Manual_D45.pdf', NULL, 'Дозаторы серии D45 находят применение в животноводческих хозяйствах с большим поголовьем. Подходят для ситуаций когда производительности популярной серии D25 оказывается недостаточно.', 'D45', 'dosatron-d45re8-vf'),
(52, 'Dosatron D8WL3000IE', '0.03 — 0.125 % [1:3000 — 1:800]', '500 л/ч — 8 м3/ч', '0.15 — 8 бар', '5 — 40 °C', 'G1½\" наружная', 'AFLAS – уплотнения, устойчивые к щелочам, для дозирования жидкостей со значением pH более 8', 'Специальный полипропилен', 'Мембранная система внешней инжекции', '697c69168087c_1769761046_Manual_D8WL.pdf', NULL, 'Серия дозаторов Water Line специально разработана компанией Dosatron для решения определенных задач водоподготовки. Модель D8WL3000IE предназначена в первую очередь для хлорирования воды. Неэлектрический двигатель, простая и надежная конструкция позволяют легко решить задачу обеззараживания воды с минимумом усилий и в кратчайшие сроки. Уникальная мембранная система внешней инжекции исключает попадание хлора внутрь двигателя дозатора, значительно увеличивает срок службы насоса и упрощает его обслуживание. Дозатор способен производить до 8 м3/ч хлорированной воды при подключении напрямую и до 80 м3/ч при подключении в системе частичного by-pass. Устройство одновременно является счетчиком воды и выставленная на ручном регуляторе пропорция дозирования будет сохраняться вне зависимости от колебаний потока и давления воды.', 'D8', 'dosatron-d8wl3000ie'),
(53, 'Dosatron D8WL2 VF', '0.2 — 2 % [1:500 — 1:50]', '500 л/ч — 8 м3/ч', '0.15 — 8 бар', '5 — 40°C', 'G1½\" наружная', 'VITON – для кислот, масел, ароматических веществ и пестицидов', 'Специальный полипропилен', '-', '697c696d3b9a0_1769761133_Manual_D8WL.pdf', NULL, 'D8WL2 VF – это обновленное наименование популярной модели D8RE2 VF, которая в свою очередь является усовершенствованной версией снятой с производства модели D8R. Новый корпус сделан из специального полипропилена, который, в отличии от полиацеталя применяемого ранее, обладает повышенной хим- и износостойкостью. Входное и выходное соединения теперь имеют стандартную резьбу 1.5 дюйма. Также применена новая эргономичная дозирующая система с удобным указателем дозировки. Дозатор обладает высокой производительностью, что делает его востребованным как в крупных животноводческих комплексах, так и для решения задач растениеводства.', 'D8', 'dosatron-d8wl2-vf'),
(54, 'Dosatron D8WL2 AF', '0.2 — 2 % [1:500 — 1:50]', '500 л/ч — 8 м3/ч', '0.15 — 8 бар', '5 — 40°C', 'G1½\" наружная', 'AFLAS – уплотнения, устойчивые к щелочам, для дозирования жидкостей со значением pH более 8', 'Специальный полипропилен', '-', '697c69bccf188_1769761212_Manual_D8WL.pdf', NULL, 'D8WL2 AF – это обновленное наименование популярной модели D8RE2 AF, которая в свою очередь является усовершенствованной версией снятой с производства модели D8R. Новый корпус сделан из специального полипропилена, который, в отличии от полиацеталя применяемого ранее, обладает повышенной хим- и износостойкостью. Входное и выходное соединения теперь имеют стандартную резьбу 1.5 дюйма. Также применена новая эргономичная дозирующая система с удобным указателем дозировки. Дозатор востребован в областях промышленности где требуется дозирование щелочных и хлорсодержащих продуктов с высокой производительностью.', 'D8', 'dosatron-d8wl2-af'),
(55, 'Dosatron D8RE5 VF', '1 — 5 % [1:100 — 1:20]', '500 л/ч — 8 м3/ч', '0.15 — 8 бар', '5 — 40°C', 'G1½\" наружная', 'VITON – для кислот, масел, ароматических веществ и пестицидов', 'Специальный полипропилен', '-', '697c6a2bdde46_1769761323_Manual_D8.pdf', NULL, 'Модель D8RE5 – это усовершенствованная версия популярной модели D8R150. Новый корпус сделан из специального полипропилена, который, в отличии от полиацеталя применяемого ранее, обладает повышенной хим- и износостойкостью. Входное и выходное соединения теперь имеют стандартную резьбу 1.5 дюйма. Также применена новая эргономичная дозирующая система с удобным указателем дозировки. Дозатор обладает высокой производительностью, что делает его востребованным как в крупных животноводческих комплексах, так и для решения задач растениеводства.', 'D8', 'dosatron-d8re5-vf'),
(56, 'Dosatron D8RE5 AF', '1 — 5 % [1:100 — 1:20]', '500 л/ч — 8 м3/ч', '0.15 — 8 бар', '5 — 40°C', 'G1½\" наружная', 'AFLAS – уплотнения, устойчивые к щелочам, для дозирования жидкостей со значением pH более 8', 'Специальный полипропилен', '-', '697c6a724fb7f_1769761394_Manual_D8.pdf', NULL, 'Модель D8RE5 – это усовершенствованная версия популярной модели D8R150. Новый корпус сделан из специального полипропилена, который, в отличии от полиацеталя применяемого ранее, обладает повышенной хим- и износостойкостью. Входное и выходное соединения теперь имеют стандартную резьбу 1.5 дюйма. Также применена новая эргономичная дозирующая система с удобным указателем дозировки. Дозатор обладает высокой производительностью.', 'D8', 'dosatron-d8re5-af'),
(57, 'Dosatron D9AL2 VF', '0.2 — 2 % [1:500 — 1:50]', '500 л/ч — 9 м3/ч', '0.3 — 8 бар', '5 — 40°C', 'G1½\" наружная', 'VITON – для кислот, масел, ароматических веществ и пестицидов', 'Специальный полипропилен', '-', '697c6ecd780b3_1769762509_Manual_D9AL.pdf', NULL, 'Модель D9AL2 (серия Animal Health Line) – это представитель нового поколения высокопроизводительных дозаторов Dosatron. Совершенно новый двигатель не только надежен и долговечен, но при этом значительно проще и удобнее в обслуживании. Никогда еще сервис двигателей высокой производительности не был таким доступным и быстрым. Корпус сделан из специального полипропилена с высокой хим- и износостойкостью. Эргономичная дозирующая система имеет удобный указатель дозировки. При сохранении внешних размеров и диаметра резьбовых соединений дозатор имеет производительность 9 м3/ч, что на 12,5 % больше чем у моделей предыдущего поколения.', 'D9', 'dosatron-d9al2-vf'),
(58, 'Dosatron D9GL2 BPVF', '0.2 — 2 % [1:500 — 1:50]', '500 л/ч — 9 м3/ч', '0.3 — 8 бар', '5 — 40°C', 'G1½\" наружная', 'VITON – для кислот, масел, ароматических веществ и пестицидов', 'Специальный полипропилен', 'Переключатель by-pass', '697cb422c6b76_1769780258_Manual_D9GL.pdf', NULL, 'Серия Green Line специально разработана для применения в области растениеводства. Корпус зеленого цвета меньше подвержен воздействию интенсивного освещения и длительное время сохраняет эстетичный внешний вид. Резиновые уплотнения из VITON\'a идеально подходят для жидких удобрений и минеральных добавок. Это следующий этап развития серии дозаторов D8. Теперь они оснащены новым двигателем, современная конструкция которого не только надежна и долговечена, но при этом значительно проще и удобнее в обслуживании. Никогда еще сервис двигателей высокой производительности не был таким доступным и быстрым. Также в стандартную комплектацию был добавлен переключатель by-pass, который позволяет без установки дополнительных кранов и трубопроводной арматуры производить запуск и остановку двигателя дозатора. Данная опция особенно удобна при использовании дозаторов в фертигационных узлах с возможностью одновременного введения нескольких добавок.', 'D9', 'dosatron-d9gl2-bpvf'),
(59, 'Dosatron D9GL5 BPVF', '1 — 5 % [1:100 — 1:20]', '500 л/ч — 9 м3/ч', '0.5 — 8 бар', '5 — 40°C', 'G1½\" наружная', 'VITON – для кислот, масел, ароматических веществ и пестицидов', 'Специальный полипропилен', 'Переключатель by-pass', '697cb485a0a09_1769780357_Manual_D9GL.pdf', NULL, 'Серия Green Line специально разработана для применения в области растениеводства. Корпус зеленого цвета меньше подвержен воздействию интенсивного освещения и длительное время сохраняет эстетичный внешний вид. Резиновые уплотнения из VITON\'a идеально подходят для жидких удобрений и минеральных добавок. Это следующий этап развития серии дозаторов D8. Теперь они оснащены новым двигателем, современная конструкция которого не только надежна и долговечена, но при этом значительно проще и удобнее в обслуживании. Никогда еще сервис двигателей высокой производительности не был таким доступным и быстрым. Также в стандартную комплектацию был добавлен переключатель by-pass, который позволяет без установки дополнительных кранов и трубопроводной арматуры производить запуск и остановку двигателя дозатора. Данная опция особенно удобна при использовании дозаторов в фертигационных узлах с возможностью одновременного введения нескольких добавок.', 'D9', 'dosatron-d9gl5-bpvf'),
(60, 'Dosatron D20AL2', '0.2 — 2 % [1:500 — 1:50]', '1000 л/ч — 20 м3/ч', '0.12 — 10 бар', '5 — 40 °C', 'Зажимное соединение на трубу 60 мм (опционально переходник на наружную резьбу G2\")', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Алюминий', '4 ноги для напольной установки, встроенный by-pass', '697cb63684547_1769780790_Manual_Notice_D20AL_EN-1.pdf', NULL, 'Серия дозаторов Water Line специально разработана компанией Dosatron для решения определенных задач водоподготовки. Модель D20WL2 – это самый большой и высокопроизводительный неэлектрический пропорциональный дозатор. При напольной установке он возвышается на 1.4 метра. Дозатор способен производить до 20 м3/ч хлорированной воды при подключении напрямую и до 200 м3/ч при подключении в системе частичного by-pass. Устройство одновременно является счетчиком воды и выставленная на ручном регуляторе пропорция дозирования будет сохраняться вне зависимости от колебаний потока и давления воды. Поскольку в данной модели отсутствует система внешней инжекции, то необходимо учитывать жесткость воды при выборе данной модели.', 'D20', 'dosatron-d20al2'),
(61, 'Dosatron D20GL2 VF', '0.2 — 2 % [1:500 — 1:50]', '1000 л/ч — 20 м3/ч', '0.12 — 10 бар', '5 — 40 °C', 'Зажимное соединение на трубу 60 мм (опционально переходник на наружную резьбу G2\")', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Алюминий', '4 ноги для напольной установки, встроенный by-pass', '697cb6b0927e9_1769780912_Manual_Notice_D20GL_EN-1.pdf', NULL, 'Модель D20GL2 (серия Green Line) – это самый большой и высокопроизводительный неэлектрический пропорциональный дозатор. При напольной установке он возвышается на 1.4 метра. Основной областью применения является дозирование жидких удобрений и других добавок для растениеводства.', 'D20', 'dosatron-d20gl2-vf'),
(62, 'Dosatron D20WL2', '0.2 — 2 % [1:500 — 1:50]', '1000 л/ч — 20 м3/ч', '0.12 — 10 бар', '5 — 40 °C', 'Зажимное соединение на трубу 60 мм (опционально переходник на наружную резьбу G2\")', 'AFLAS – уплотнения, устойчивые к щелочам, для дозирования жидкостей со значением pH более 8', 'Алюминий', '4 ноги для напольной установки, встроенный by-pass', '697cb719a87da_1769781017_Rangesheet_FichesGamme_D20S_EN-3.pdf', NULL, 'Серия дозаторов Water Line специально разработана компанией Dosatron для решения определенных задач водоподготовки. Модель D20WL2 – это самый большой и высокопроизводительный неэлектрический пропорциональный дозатор. При напольной установке он возвышается на 1.4 метра. Дозатор способен производить до 20 м3/ч хлорированной воды при подключении напрямую и до 200 м3/ч при подключении в системе частичного by-pass. Устройство одновременно является счетчиком воды и выставленная на ручном регуляторе пропорция дозирования будет сохраняться вне зависимости от колебаний потока и давления воды. Поскольку в данной модели отсутствует система внешней инжекции, то необходимо учитывать жесткость воды при выборе данной модели.', 'D20', 'dosatron-d20wl2'),
(63, 'Dosatron D20S VF', '0.2 — 2 % [1:500 — 1:50]', '1000 л/ч — 20 м3/ч', '0.12 — 10 бар', '5 — 40 °C', 'Зажимное соединение на трубу 60 мм (опционально переходник на наружную резьбу G2\")', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Алюминий', '4 ноги для напольной установки, встроенный by-pass', '697cb8d4eb0c8_1769781460_Rangesheet_FichesGamme_D20S_EN-2.pdf', NULL, 'Модель D20S – это самый большой и высокопроизводительный неэлектрический пропорциональный дозатор. При напольной установке он возвышается на 1.4 метра. Основной областью применения является дозирование жидких удобрений и других добавок для растениеводства. Также используется в специализированных комплексах пожаротушения и в любых других отраслях, требующих обработки большого количества воды в сжатые сроки.', 'D20', 'dosatron-d20s-vf'),
(64, 'Dosatron D30GL02 VF', '0.02 — 0.2 % [1:5000 — 1:500]', '8000 л/ч — 30 м³/ч', '0.5 — 6 бар', '5 — 40 °C', 'G3\" наружная или фланцы DN80 ISO', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Специальный полипропилен', 'Переключатель by-pass', '697cbaccdc945_Manual_Notice_D30GL-1_compressed_compressed__1__compressed-____________.pdf', NULL, 'Уникальная модель D30GL02 (серия Green Line) способна обеспечить рекордную производительность до 30000 л/ч. Это достигается за счет пропорционально разделения потока с помощью новой запатентованной технологии дозатрон. При этом за сам процесс дозирования отвечает хорошо себя зарекомендовавший дозатор серии D3. В результате легкость и стоимость обслуживания этого высокопроизводительного дозатора будет сравнима с обычным 3-х кубовым дозатором.', 'D30', 'dosatron-d30gl02-vf'),
(65, 'Dosatron D30GL1 VF', '0.1 — 1 % [1:1000 — 1:100]', '8000 л/ч — 30 м³/ч', '0.5 — 6 бар', '5 — 40 °C', 'G3\" наружная или фланцы DN80 ISO', 'VITON – для кислот, масел, ветеринарных препаратов, ароматических веществ и пестицидов', 'Специальный полипропилен', 'Переключатель by-pass', '697cbb3c8c957_1769782076_Manual_Notice_D30GL-1_compressed_compressed__1__compressed-____________.pdf', NULL, 'Уникальная модель D30GL1 (серия Green Line) способна обеспечить рекордную производительность до 30000 л/ч. Это достигается за счет пропорционально разделения потока с помощью новой запатентованной технологии дозатрон. При этом за сам процесс дозирования отвечает хорошо себя зарекомендовавший дозатор серии D3. В результате легкость и стоимость обслуживания этого высокопроизводительного дозатора будет сравнима с обычным 3-х кубовым дозатором.', 'D30', 'dosatron-d30gl1-vf'),
(66, 'Медикатор Master PRO 3-10%', '3 — 10% [1:33 — 1:10]', '10-2.5м³/ч', '0.25-5 Бар', '5℃-40℃', '3/4’', 'Антиоксидант: да', 'пластик', '-', '', '', '[p][b]Медикаторы Master PRO 3-10%[/b]— это уникальный дозирующий насос, предназначенный для точного дозирования различных растворов. MASTER PRO предлагает  дозирующие насосы (медикаторы) для различного применения, например, в качестве дозаторов лекарства для скота, для очистки или дезинфекции жидкостного потока, для дезинфекции систем водоснабжения, мойки машин, для экономически эффективного внесения жидких удобрений, для борьбы с вредителями сельскохозяйственных культур и растений. Инжекторы медикатора легко адаптируются, просты в использовании и экономически эффективны, что немаловажно для эффективного и долгосрочного планирования.[/p]\r\n[p]Дозирующий насос Master PRO в одном лице представляет медикатор для птицеводства и медикатор для КРС.[/p]\r\n[h2]Принцип работы дозирующего насоса Master Pro 3-10%[/h2]\r\n[p]Принцип работы дозирующего насоса для химических средств, лекарств и других жидкостей основывается на положениях гидравлики. Медикатор не требует подключения к источнику элекропитания или воздействия иных сил. Для работы дозирующего насоса необходимо только давление постоянно водяного потока, двигающегося по трубопроводу. Как только вода под давлением поступает внутрь дозирующего насоса, гидровлический привод приходите в действие, который в свою очередь приводит в движение поршень дозирующей системы насоса. Медикатор всасывает жидкообразную добавку, а затем вводит в проходящий поток воды строго установленную дозу жидкой добавки. Полученная смесь тщательно перемешивается внутри двигателя дозирующего насоса и только затем подается в трубопровод.[/p]', 'Master Pro', 'medikator-master-pro-3-10-2'),
(67, 'Медикатор Master PRO 0,2-2%', '0.2 — 2 % [1:500 — 1:50]', '10 л/ч — 2.5 м³/ч [0.16 — 41.66 л/мин]', '0.25-5 Бар', '5 — 40 °C', 'G¾\" наружная', 'пластик', 'пластик', 'Есть защита от хлорирования, есть антиоксиданты', '', '', '[p][b]Медикаторы Master PRO 0,2-2%[/b] — это уникальный дозирующий насос, предназначенный для точного дозирования различных растворов. MASTER PRO предлагает  дозирующие насосы (медикаторы) для различного применения, например, в качестве дозаторов лекарства для скота, для очистки или дезинфекции жидкостного потока, для дезинфекции систем водоснабжения, мойки машин, для экономически эффективного внесения жидких удобрений, для борьбы с вредителями сельскохозяйственных культур и растений. Инжекторы медикатора легко адаптируются, просты в использовании и экономически эффективны, что немаловажно для эффективного и долгосрочного планирования.[/p]\r\n[p]Дозирующий насос Master PRO в одном лице представляет медикатор для птицеводства и медикатор для КРС.[/p]\r\n[h2]Преимущества медикатора Master Pro 0,2-2%:[/h2]\r\n[ul][li]для работы дозирующего насоса (медикатора) не требуется подключение к электроэнергии;\r\n[/li]\r\n[li]доза препарата точно регулируется при установке в линию;\r\n[/li][li]конструкция медикатора позволяет его разобрать и промыть;\r\n[/li][li]дозирующая система насоса позволяет соблюдать однородность и точную дозировку вводимых препаратов.\r\n[/li][/ul]\r\n[h2]Принцип работы медикатора Master Pro 0,2-2%[/h2]\r\n[p]Принцип работы дозирующего насоса для химических средств, лекарств и других жидкостей основывается на положениях гидравлики. Медикатор не требует подключения к источнику элекропитания или воздействия иных сил. Для работы дозирующего насоса необходимо только давление постоянно водяного потока, двигающегося по трубопроводу. Как только вода под давлением поступает внутрь дозирующего насоса, гидровлический привод приходите в действие, который в свою очередь приводит в движение поршень дозирующей системы насоса. Медикатор всасывает жидкообразную добавку, а затем вводит в проходящий поток воды строго установленную дозу жидкой добавки. Полученная смесь тщательно перемешивается внутри двигателя дозирующего насоса и только затем подается в трубопровод.[/p]', 'Master Pro', 'medikator-master-pro-0-2-2');
INSERT INTO `medicator` (`id`, `name`, `d_dosing`, `performance`, `pressure`, `temperature`, `connections`, `m_seal`, `m_case`, `dop`, `passport`, `user_pass`, `opis`, `filtr`, `slug`) VALUES
(68, 'Медикатор Master PRO 1-5%', '1 - 5 % [1:100 — 1:20]', '10л/ч - 2.5м³/ч', '0.25-5 Бар', '5 — 40 °C', 'G¾\"', 'пластик', 'пластик', 'Защита от хлорирования: да, антиоксидант: да', '', '', '[p][b]Медикаторы Master PRO 1-5%[/b] — это уникальный дозирующий насос, предназначенный для точного дозирования различных растворов. MASTER PRO предлагает дозирующие насосы (медикаторы) для различного применения, например, в качестве дозаторов лекарства для скота, для очистки или дезинфекции жидкостного потока, для дезинфекции систем водоснабжения, мойки машин, для экономически эффективного внесения жидких удобрений, для борьбы с вредителями сельскохозяйственных культур и растений. Инжекторы медикатора легко адаптируются, просты в использовании и экономически эффективны, что немаловажно для эффективного и долгосрочного планирования.\r\n[/p]\r\n[p]Дозирующий насос Master PRO в одном лице представляет медикатор для птицеводства и медикатор для КРС.[/p]\r\n[h2]Принцип работы медикатора Master Pro 1-5%[/h2]\r\n[p]Принцип работы дозирующего насоса для химических средств, лекарств и других жидкостей основывается на положениях гидравлики. Медикатор не требует подключения к источнику элекропитания или воздействия иных сил. Для работы дозирующего насоса необходимо только давление постоянно водяного потока, двигающегося по трубопроводу. Как только вода под давлением поступает внутрь дозирующего насоса, гидровлический привод приходите в действие, который в свою очередь приводит в движение поршень дозирующей системы насоса. Медикатор всасывает жидкообразную добавку, а затем вводит в проходящий поток воды строго установленную дозу жидкой добавки. Полученная смесь тщательно перемешивается внутри двигателя дозирующего насоса и только затем подается в трубопровод.[/p]\r\n[h2]Преимущества медикатора Master Pro 1-5%:[/h2]\r\n[ul][li]для работы дозирующего насоса (медикатора) не требуется подключение к электроэнергии;\r\n[/li][li]доза препарата точно регулируется при установке в линию;\r\n[/li][li]конструкция медикатора позволяет его разобрать и промыть;\r\n[/li][li]дозирующая система насоса позволяет соблюдать однородность и точную дозировку вводимых препаратов.[/li][/ul]', 'Master Pro', 'medikator-master-pro-1-5'),
(69, 'Mixtron MX.075.P022', '0,2 - 2 %', 'от 5 до 750 л/ч', 'от 0,5 до 6 бар', '5° - 40° C', 'G\'3/4', 'VITON, рекомендованный для кислот, масел, ветеринарных препаратов, ароматиков и пестицидов', 'состоит из POM, PP, HDPE, PVDF', '-', NULL, NULL, '[H2]Mixtron MX.075.P022 | Дозирующий насос Микстрон[/H2]\r\n[p]Насос дозирующий Mixtron MX.075.P022 – высококачественный насос-дозатор, предназначенный для точного дозирования и смешивания с питьевой водой вакцин, витаминов и других препаратов животным и птицам.[/p]\r\n\r\n[h3]Применение медикатора Mixtron MX.075.P022[/h3]\r\n[p]Основное использование насоса-дозатора MIXTRON MX.075.P022 — доставка вакцин, витаминов и других препаратов животным и птицам через питьевую воду. Однако дозирующие насосы также могут использоваться для дезинфекции, введения удобрений, очистки водных сетей, фитообработки, корректировки pH, смазки, мойки автомобилей и прочего.[/p]\r\n\r\n[p]Медикатор MIXTRON, подключенный к водопроводу, исключительно использует давление воды для работы благодаря уникальным технологиям. Дозаторы MIXTRON обеспечивают непрерывное пропорциональное всасывание концентрата, последующего смешения с водой, а затем направляют полученный раствор в сеть. Встроенные системы автоматического регулирования дозируют вещество в зависимости от объема воды.[/p]', 'MX075', 'mixtron-mx-075-p022'),
(70, 'Медикатор Save Water XS2502', '0.3-2%[1:333-1:50]', '7-2500 Л/ч', '0.2-8 Бар', '4-40℃', '3/4”', '-', '-', '-', '', '', '[h2]Дозирующий насос Save Water XS2502\r\n[/h2][p]Дозирующий насос Save Water XS2502 – это высокоэффективный медикатор, предназначенный для точного дозирования химических средств и реагентов. Этот насос идеально подходит для использования в птицеводстве, животноводческих комплексах и на фермах. Изготовлен из высококачественных материалов, обеспечивающих долговечность и надежность.\r\n[/p]\r\n[h3]Применение медикатора Save Water XS2502\r\n[/h3][p]Медикатор Save Water XS2502 широко используется для дозирования лекарственных препаратов и химических средств в системах водоснабжения. Он идеально подходит для птицефабрик, ферм и ветеринарных клиник, обеспечивая точное и равномерное распределение реагентов.\r\n[/p]\r\n[h3]Медикатор Save Water XS2502 поможет дозировать следующие препараты:[/h3]\r\n[ul][li]Антибиотики[/li]\r\n[li]Вакцины[/li]\r\n[li]Дезинфицирующие средства\r\n[/li]Уксусную кислоту\r\n[li]Хлоросодержащие средства\r\n[/li]Всевозможные добавки\r\n[li]Витамины[/li]\r\n[li]Минералы[/li]\r\n[li]Очищающее средство\r\n[/li][/ul][h3]Принцип работы дозирующего насоса Save Water XS2502 для птицеводства и КРС[/h3]\r\nПринцип работы медикатора Save Water XS2502 основан на гидравлических законах, и устройство не требует подключения к электропитанию или другим внешним источникам энергии. Для функционирования дозирующего насоса необходимо лишь постоянное давление водного потока в трубопроводе. Когда вода под давлением поступает в насос, гидравлический привод активируется и приводит в движение поршень дозирующего механизма. Поршень всасывает жидкую добавку и вводит её в поток воды в точно заданной дозировке. Полученная смесь тщательно перемешивается внутри насоса, прежде чем поступить обратно в трубопровод.\r\n\r\nМедикатор Save Water XS2502 не требует электричества, так как в качестве движущей силы используется только напор воды. Приводимый в действие, таким образом, он всасывает концентрированный продукт, дозирует с желаемым процентным содержанием, а затем перемешивает с движущейся водой. Полученный раствор направляется вниз по сети.\r\n\r\nДоза впрыскиваемого продукта всегда пропорциональна объему проходящей через медикатор воды, независимо от колебаний расхода воды или давления в сети. Дозировка отображается в % соотношении, что позволяет очень просто рассчитать объем требуемого препарата.\r\n\r\npH среда воды влияет на срок эксплуатации продукта, особенно от сильнокислотных или сильнощелочных препаратов страдают уплотнительные кольца и нижняя часть корпуса медикатора, которая непосредственно забирает препарат из бака лекарств. Поэтому важной характеристик', 'XS', 'save-water-xs2502'),
(71, 'Медикатор Save Water XS2504', '0.4-4% [1:250 - 1:25]', '7-2500 Л/ч', '0.2-8 Бар', '4-40℃', '3/4”', '-', '-', '-', '', '', '[h2]Дозирующий насос Save Water XS2504\r\n[/h2][p]Дозирующий насос Save Water XS2504 – это высокоэффективный медикатор, предназначенный для точного дозирования химических средств и реагентов. Этот насос идеально подходит для использования в птицеводстве, животноводческих комплексах и на фермах. Изготовлен из высококачественных материалов, обеспечивающих долговечность и надежность.[/p]\r\n\r\n[h3]Применение медикатора Save Water XS2504\r\n[/h3][p]Медикатор Save Water XS2504 широко используется для дозирования лекарственных препаратов и химических средств в системах водоснабжения. Он идеально подходит для птицефабрик, ферм и ветеринарных клиник, обеспечивая точное и равномерное распределение реагентов.[/p]\r\n\r\n[h3]Медикатор Save Water XS2504 поможет дозировать следующие препараты:\r\n[/h3]\r\n[ul][li]Антибиотики[/li]\r\n[li]Вакцины[/li]\r\n[li]Дезинфицирующие средства\r\n[/li][li]Уксусную кислоту[/li]\r\n[li]Хлоросодержащие средства\r\n[/li][li]Всевозможные добавки[/li]\r\n[li]Витамины[/li]\r\n[li]Минералы\r\n[/li][li]Очищающее средство[/li][/ul]\r\n[h3]Принцип работы медикатора Save Water XS2504 для птицеводства и КРС\r\n[/h3][p]Принцип работы медикатора Save Water XS2504 основан на гидравлических законах, и устройство не требует подключения к электропитанию или другим внешним источникам энергии. Для функционирования дозирующего насоса необходимо лишь постоянное давление водного потока в трубопроводе. Когда вода под давлением поступает в насос, гидравлический привод активируется и приводит в движение поршень дозирующего механизма. Поршень всасывает жидкую добавку и вводит её в поток воды в точно заданной дозировке. Полученная смесь тщательно перемешивается внутри насоса, прежде чем поступить обратно в трубопровод.\r\n\r\nМедикатор Save Water XS2504 не требует электричества, так как в качестве движущей силы используется только напор воды. Приводимый в действие, таким образом, он всасывает концентрированный продукт, дозирует с желаемым процентным содержанием, а затем перемешивает с движущейся водой. Полученный раствор направляется вниз по сети.\r\n\r\nДоза впрыскиваемого продукта всегда пропорциональна объему проходящей через медикатор воды, независимо от колебаний расхода воды или давления в сети. Дозировка отображается в % соотношении, что позволяет очень просто рассчитать объем требуемого препарата.\r\n\r\npH среда воды влияет на срок эксплуатации продукта, особенно от сильнокислотных или сильнощелочных препаратов страдают уплотнительные кольца и нижняя часть корпуса медикатора, которая непосредственно забирает препарат из бака лекарств. Поэтому важной х', 'XS', 'save-water-xs2504'),
